<script>
import LeadDataService from "../../../services/DataService";

export default {
    props: {
        modalCallItem: null
    },
    data: function () {
        return {
            Id: 0,
            isLoading: false,
            contactName: '',
            Subject: '',
            callPurpose: '',
            relatedTo: '',
            callScheduleTime: new Date(),
            Description: '',
            Users: [],
            UserValue: '',
            modal: null,
            isView: false,
            popover: {
                visibility: 'click'
            },
            optionsMindate: {
                format: 'MMM dd yyyy',
                useCurrent: false,
                showClear: true,
                showClose: true,
                allowInputToggle: true,
                minDate: new Date(Date.now()),

            },
        }
    },
    created: function () {
        debugger
        this.GetUsers();
        this.modal = this.modalCallItem;
        if (this.modal != null) {
            this.EditModel(this.modal);
            this.isView = true;
        }

    },
    methods: {
        EditModel(item) {
            debugger
            var vm = this;
            vm.Id = item.followup_notification_id;
            vm.UserValue = item.contact_person;
            vm.callScheduleTime = item.followup_notification_schedule;
            vm.Subject = item.followup_notification_subject;
            vm.callPurpose = item.call_purpose;
            vm.Description = item.followup_notification_message;
        },
        GetUsers: function () {
            var vm = this;
            var url = `id=&moduleName=${vm.$route.params.moduleName}&type=USERS`;

            LeadDataService.getLeaOwnerBySearch(url).then(function (response) {
                var json = response.data;

                if (json != null) {
                    vm.Users = json.DATA;
                    return vm.Users;
                }

            });
        },
        getSelectedValue: function (event) {
            this.UserValue = event.target.value;
        },
        formatDate: function (value) {
            if (value) {
                var timeFormat = 'h:mm A';
                try {
                    timeFormat = String(timeFormat).replace("t", "A").replace("t", "");
                    var getDate = new Date(moment(String(value)).year(), moment(String(value)).month(), moment(String(value)).date(), moment(String(value)).hours(), moment(String(value)).minutes());
                    return moment(getDate, "YYYY-MM-DD HH:mm:ss").format(String("MM-dd-yyyy").toUpperCase() + " " + String(timeFormat));
                } catch (e) {
                    timeFormat = 'h:mm A';
                    timeFormat = String(timeFormat).replace("t", "a").replace("t", "");
                    return moment(String(value)).format(String("MM-dd-yyyy").toUpperCase() + " " + String(timeFormat));
                }
            }
        },
        SaveScheduleCall: function (values) {
            //   this.$refs.form.setFieldTouched('Subject', true);  
            //   this.$refs.form.setFieldTouched('schedule', true); 
            //   this.$refs.form.setFieldTouched('Description', true); 
            //   this.$refs.form.setFieldTouched('callPurpose', true); 
            //   this.$refs.form.setFieldTouched('name', true);  
            //    this.$refs.form.setFieldTouched('UserValue', true);        
            var vm = this;
            this.$refs.form.validate().then((result) => {
                //     if(values['UserValue']){
                //         delete result.errors.UserValue;
                //         result.results['UserValue'].valid=true;
                //         result.results['UserValue'].errors=[];
                //         result.valid= Object.keys(result.errors).length === 0?true:result.valid;
                // }
                if (result) {
                    this.isLoading = true;
                    $('#Fields_mandatory').hide();
                    var data = {
                        sourceId: vm.$route.params.id,
                        moduleName: vm.$route.params.moduleName,
                        subModuleCode: vm.$route.params.subModuleCode,
                        contactid: vm.UserValue,
                        subjectText: vm.Subject,
                        callpurpose: vm.callPurpose,
                        callScheduletime: vm.callScheduleTime,
                        description: vm.Description,
                        activityId: vm.Id == null ? 0 : vm.Id,
                        activityType: "Call"
                    };

                    var expDate = vm.$parent.expirydate;
                    if (expDate != null) {
                        var newExp = new Date(expDate)
                        var DueDate = new Date(vm.callScheduleTime);
                        if (DueDate > newExp) {
                            vm.ShowAlert(vm.$t("Schedule date can not be greater than expected close date."), "warning", true, vm.$t("Alert"));
                            vm.callScheduleTime = "";
                            return false;
                        }
                    }

                    var objectPostString = JSON.stringify(data)
                    LeadDataService.SaveScheduleCall(objectPostString).then(function (response) {
                        debugger
                        if (response.data[0].Status == "Success") {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Call')]), "success", true, vm.$t("Alert"));
                        }
                        else if (response.data = "UPDATE") {
                            vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Call')]), "success", true, vm.$t("Alert"));

                        }
                        vm.duedate = "";
                        vm.Subject = "";
                        vm.priority = "";
                        vm.Message = "";
                        vm.showAddTaskModal = false;
                        vm.$emit('close');
                        vm.$parent.loadData('activities');
                        vm.isLoading = false;
                    });
                }
            });
        },
        // FetchCallViewData: function (id) {
        //     var vm = this;
        //     var url = "id=" + id + "&refId=" + this.$route.params.id + "&subModuleCode=" + this.$route.params.subModuleCode + "&moduleCode=" + this.$route.params.moduleName;
        //     LeadDataService.updateActivityData(url).then(function (response) {

        //         if (response.data != null) {
        //             var data = response.data.data;
        //             vm.UserValue = data[0].contact_person;
        //             vm.callScheduleTime = data[0].followUpDate;
        //             vm.callPurpose = data[0].call_purpose;
        //             vm.Subject = data[0].followup_notification_subject;
        //             vm.Description = data[0].followup_notification_message;
        //             var frmFields = {}
        //             frmFields['UserValue'] = vm.UserValue;

        //             frmFields['callPurpose'] = vm.callPurpose;
        //             frmFields['Subject'] = vm.Subject;
        //             frmFields['Description'] = vm.Description;
        //             // vm.$refs.form.resetForm({values:frmFields});
        //         }
        //     });
        // }
    }
}

</script>

<template>

    <div class="modal d-block my-popups dialog">
        <loader :is-visible="isLoading"></loader>
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <slot name="header">
                        <h5>{{ $t('ScheduleCall') }}</h5>
                    </slot>
                    <button type="button" title="" v-on:click="$emit('close')" class="close"
                        data-original-title="Close"><em class="fa fa-times" aria-hidden="true"></em></button>
                </div>
                <div class="modal-body">
                    <div class="row form-head" style="display:none">
                        <div class="col-12">
                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4 float-right p-0">
                                <div class="userguide-box userguide_curve">
                                    <a data-toggle="collapse" href="#user-guidepriority" aria-expanded="false"
                                        aria-controls="search-content" class="userguide-btn collapsed"><em
                                            class="fa"></em><span>@Resources.UserGuide</span></a>
                                    <div class="clearfix"></div>
                                    <div id="user-guidepriority" class="user-guide collapse">
                                        {{ $t('FillFormtoaddScheduleCall') }} <br><br>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <Form ref="form" v-slot="{ valid, errors }">
                        <div class="d-flex flex-wrap">
                            <div class="col-md-12 p-0">
                                <div class="row">
                                    <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                                        <div class="form-group">
                                            <label>{{ $t('ContactName') }} :<span class="text-danger">*</span></label>
                                            <Field name="Contact Name" :rules="{ 'required': true }"
                                                v-slot="{ errors }">
                                                <select v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    v-model="UserValue" name="UserValue" v-on:change="getSelectedValue">
                                                    <option value="">{{ $t('SelectContact') }} </option>
                                                    <option v-for="user in Users" v-bind:value="user.value" :Key="user">
                                                        {{ user.name }}
                                                    </option>
                                                </select>
                                                <span name="Contact Name" class="invalid-feedback d-block">{{ errors[0]
                                                    }}</span>
                                            </Field>



                                        </div>
                                    </div>
                                    <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                                        <div class="form-group">
                                            <label>{{ $t('Notification') }} {{ $t('Schedule') }} :<span
                                                    class="text-danger">*</span></label>
                                            <div class="input-group">
                                                <Field name="Schedule" :rules="{ 'required': true }"
                                                    v-slot="{ errors }">
                                                    <v-date-picker :popover="popover" :minute-increment="5"
                                                        mode="dateTime" class="input-group" v-model="callScheduleTime">
                                                        <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                            <input
                                                                :class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                                :value="inputValue" v-on="inputEvents" />
                                                            <div @click="togglePopover()" class="input-group-append">
                                                                <span class="input-group-text"><em
                                                                        class="fa fa-calendar"></em></span>
                                                            </div>
                                                        </template>
                                                    </v-date-picker>
                                                    <span name="Schedule" class="invalid-feedback d-block">{{ errors[0]
                                                        }}</span>
                                                </Field>

                                            </div>
                                        </div>
                                    </div>
                                    <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                                        <div class="form-group">
                                            <label>{{ $t('Subject') }}:<span class="text-danger">*</span></label>
                                            <Field name="Subject" :rules="{ 'required': true }" v-slot="{ errors }">
                                                <input v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    id="Subject" name="Subject" maxlength="200" v-model="Subject"
                                                    type="text" />
                                                <span name="Subject" class="invalid-feedback d-block">{{ errors[0]
                                                    }}</span>
                                            </Field>
                                        </div>
                                    </div>
                                    <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                                        <div class="form-group">
                                            <label>{{ $t('callPurpose') }}:<span class="text-danger">*</span></label>
                                            <Field name="Call Purpose" :rules="{ 'required': true }"
                                                v-slot="{ errors }">
                                                <input v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    id="callPurpose" name="callPurpose" maxlength="200"
                                                    v-model="callPurpose" type="text" />
                                                <span name="Call Purpose" class="invalid-feedback d-block">{{ errors[0]
                                                    }}</span>
                                            </Field>

                                        </div>
                                    </div>
                                    <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left">
                                        <div class="form-group">
                                            <label>Description:<span class="text-danger">*</span></label>
                                            <Field name="Description" :rules="{ 'required': true }" v-slot="{ errors }">
                                                <textarea v-model="Description"
                                                    v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }"
                                                    maxlength="1000" name="Description" rows="5"></textarea>
                                                <span name="Description" class="invalid-feedback d-block">{{ errors[0]
                                                    }}</span>
                                            </Field>
                                        </div>
                                    </div>
                                </div>
                                <div class="row flex-row-reverse">
                                    <div class="col-lg-6 text-right">
                                        <a href="javascript:;" class="btn btn-success save-btn mr-1" title=""
                                            id="anctransferloaddata" v-on:click="SaveScheduleCall(valid, errors)"><em
                                                class="fa fa-save pr-2"></em>{{ $t('Save') }}</a>
                                        <a href="javascript:;" v-on:click="$emit('close')"
                                            class="btn btn-danger delete-btn"><em class="fa fa-times"></em>
                                            {{ $t('Cancel') }}</a>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="py-2">
                                            <span class="mandatory"> {{ $t('MandatoryString') }} </span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    </div>

</template>
